import java.io.*;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

public class SecureXSSProtection {
    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter your name: ");
            String name = reader.readLine();

            // Sanitize and escape user input using ESAPI HTML entity encoding
            HTMLEntityCodec codec = new HTMLEntityCodec();
            String sanitizedName = codec.encodeForHTML(name);

            System.out.println("<p>Welcome, " + sanitizedName + "!</p>");
        } catch (IOException e) {
            System.err.println("Error reading input.");
        }
    }
}

